The code below tries to print how many milliseconds a loop takes, but will not compile. What is wrong?

```cpp
#include <iostream>
#include <chrono>
int main()
{
    auto start = std::chrono::steady_clock::now();
    long long s = 0;
    for (int i = 0; i < 1000000; ++i) s += i;
    auto end = std::chrono::steady_clock::now();
    auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(end - start);
    std::cout << "Elapsed: " << elapsed << " ms\n";  // problem here
    std::cout << s << '\n';
    return 0;
}
```

Ignoring the actual elapsed time (which varies by machine), what is the structure of the output printed by the following program?

```cpp
#include <iostream>
#include <chrono>
int main()
{
    auto t1 = std::chrono::steady_clock::now();
    int x = 0;
    for (int i = 0; i < 100; ++i) x += i;
    auto t2 = std::chrono::steady_clock::now();
    auto ms = std::chrono::duration_cast<std::chrono::milliseconds>(t2 - t1).count();
    std::cout << "Result: " << x << '\n';
    std::cout << "Time: " << ms << " ms\n";
    return 0;
}
```
